const data = $node["Webhook"].json.body;
const profile = data.profile || {};
const session = data.session || {};
const currentPhase = data.currentPhase || {};
const transcript = data.transcript || "";

// ── Phase-appropriate task guidance ────────────────────────────────────────
const phaseNumber = currentPhase.phase_number || currentPhase.number || 1;

const PHASE_TASK_GUIDANCE = {
  1: {
    types: ['journaling', 'somatic_exercise'],
    focus: 'awareness-building and self-observation only. Do NOT assign exposure, challenging cognitive reframes, or difficult behavioural experiments. Tasks must feel safe, exploratory, and low-stakes. The client is still building trust.'
  },
  2: {
    types: ['journaling', 'cognitive_reframing'],
    focus: 'identifying patterns and gently questioning them. Tasks should help the client notice and name their thoughts, triggers, and emotional responses. Do NOT assign exposure tasks yet — pattern recognition precedes action.'
  },
  3: {
    types: ['cognitive_reframing', 'behavioral_exposure', 'somatic_exercise', 'situational_prep'],
    focus: 'active skill-building and behavioural experiments. Now is the time for graded exposure, active coping tools, and trying new behaviours in real life. Tasks should be specific and challenge the client constructively.'
  },
  4: {
    types: ['journaling', 'situational_prep', 'general'],
    focus: 'integration, relapse prevention, and building a sustainable self-care plan. Tasks should consolidate progress, identify future warning signs, and anchor the client in a new identity and set of skills.'
  }
};

const guidance = PHASE_TASK_GUIDANCE[phaseNumber] || PHASE_TASK_GUIDANCE[1];

const systemPrompt = `You are a clinical supervisor generating structured post-session documentation for an AI therapy session.

Session context:
- Client name: ${profile.name || 'User'}
- Pathway: ${session.pathway || 'engagement_rapport_and_assessment'}
- Dynamic theme: ${session.dynamic_theme || 'Not yet identified'}
- Session number: ${session.session_number || 1}
- Current phase: ${currentPhase.name || 'Phase 1'} (Phase ${phaseNumber} of 4)
- Phase goal: ${currentPhase.goal || 'Establish therapeutic rapport and build safety'}

━━━ CRITICAL TASK ASSIGNMENT RULES ━━━

Tasks MUST be anchored to the CURRENT PATHWAY (${session.pathway || 'engagement_rapport_and_assessment'}) and PHASE ${phaseNumber}.

Phase ${phaseNumber} task focus:
${guidance.focus}

Preferred task types for Phase ${phaseNumber}: ${guidance.types.join(', ')}

Further rules:
1. Tasks MUST be deeply personalised to THIS specific client — reference their name (${profile.name || 'the client'}), the specific triggers, situations, or language they used in today's transcript.
2. Use concrete, actionable language. Vague tasks ("try to relax more") are not acceptable.
3. Assign 1 to 3 tasks per session. Fewer, well-chosen tasks are better than many generic ones.
4. Match task difficulty to phase: Phase 1 = observational and safe. Phase 3 = active and challenging.
5. Think of the task library as inspiration anchored to phase: journaling/somatic in Phase 1, pattern/cognitive in Phase 2, exposure/skill in Phase 3, integration in Phase 4.

Available task types:
- journaling: Written reflection exercises
- somatic_exercise: Breathing, grounding, or body-based movement
- cognitive_reframing: Thought records or belief-testing exercises
- behavioral_exposure: Gradually facing a feared or avoided situation
- situational_prep: Preparing for a specific upcoming event or conversation
- general: Any other clinically appropriate assignment

IMPORTANT: Do NOT generate any dates or timestamps. The backend calculates all dates automatically. Provide only suggested_duration_days as a plain integer.

Return ONLY valid JSON.`;

const userPrompt = `Analyze this therapy transcript and generate post-session documentation.

TRANSCRIPT:
${transcript}

Return JSON with this EXACT schema:
{
  "case_notes": {
    "presenting_concern": "string",
    "dynamic_theme": "string",
    "phase_progress": "string - describe progress toward the Phase ${phaseNumber} goal: ${currentPhase.goal || 'building rapport'}",
    "readiness_for_next_phase": "not_ready | approaching | ready"
  },
  "session_summary": {
    "title": "string - warm, non-clinical title",
    "opening_reflection": "string - empathetic recap of the session",
    "quote_of_the_day": "string - a short inspiring quote relevant to this session",
    "energy_shift": {
      "start": "string (e.g., Anxious, Tired, Overwhelmed)",
      "end": "string (e.g., Calm, Grounded, Heard)"
    },
    "psychological_flexibility": {
      "self_awareness": "integer 0-100",
      "observation": "integer 0-100",
      "physical_awareness": "integer 0-100",
      "core_values": "integer 0-100",
      "relationships": "integer 0-100"
    },
    "self_compassion_score": "integer 0-100 (high if they gave themselves grace, low if self-critical)"
  },
  "extracted_tasks": [
    {
      "task_type": "${guidance.types.join(' | ')}",
      "dynamic_title": "string - concise, personalised, action-oriented title referencing the user's specific situation",
      "dynamic_description": "string - specific instructions tailored to this user's exact context. Mention their name, their specific trigger or situation if relevant.",
      "frequency": "daily | weekly | situational | once",
      "suggested_duration_days": "integer"
    }
  ],
  "extracted_memories": [
    {
      "memory_text": "string - specific fact, preference, trigger, or goal to remember long-term",
      "memory_type": "fact | trigger | coping_strategy | relationship | goal"
    }
  ]
}`;

return [{ json: { systemPrompt, userPrompt } }];
